function randomInt(n,t){return Math.floor(Math.random()*(t-n+1))+n}function randomChoice(n){if(!n||0===n.length)throw new Error("randomChoice: cannot pick from an empty array.");return n[randomInt(0,n.length-1)]}function shuffleArray(n){const t=n.slice();for(let n=t.length-1;n>0;n--){const e=randomInt(0,n);[t[n],t[e]]=[t[e],t[n]]}return t}function clamp(n,t,e){return Math.min(Math.max(n,t),e)}function range(n,t,e=1){const r=[];for(let o=n;o<=t;o+=e)r.push(o);return r}function ordinal(n){const t=n%100;return n+(t>=11&&t<=13?"th":["th","st","nd","rd"][n%10]||"th")}function escapeHtml(n){const t=document.createElement("div");return t.textContent=n,t.innerHTML}function getById(n){return document.getElementById(n)}function showElement(n){n.classList.remove("u-hidden")}function hideElement(n){n.classList.add("u-hidden")}